// Ingesta: correlaciona ubicacion + foto por chat y las guarda en staticData.
// El token del bot: mejor como variable de entorno TELEGRAM_BOT_TOKEN.
const token = $env.TELEGRAM_BOT_TOKEN || 'PEGA_TU_TOKEN_AQUI';
const sd = $getWorkflowStaticData('global');
sd.photos = sd.photos || [];
sd.pending = sd.pending || {};

const upd = $json.message || $json.channel_post || $json;
const msg = upd.message ? upd.message : upd;
const chatId = msg.chat && msg.chat.id;

async function reply(text){
  if(!chatId) return;
  try{ await this.helpers.httpRequest({ method:'POST', url:`https://api.telegram.org/bot${token}/sendMessage`, body:{ chat_id: chatId, text }, json:true }); }catch(e){}
}

let out = { handled:false };

if (msg.location){
  sd.pending[chatId] = { lat: msg.location.latitude, lon: msg.location.longitude };
  await reply.call(this, '📍 Ubicación recibida. Ahora envíame la foto y la ubicaré en el mapa.');
  out = { handled:'location', lat: msg.location.latitude, lon: msg.location.longitude };
}
else if (msg.photo && msg.photo.length){
  const fileId = msg.photo[msg.photo.length-1].file_id; // mayor resolución
  const gf = await this.helpers.httpRequest({ url:`https://api.telegram.org/bot${token}/getFile`, qs:{ file_id: fileId }, json:true });
  const filePath = gf.result && gf.result.file_path;
  const url = `https://api.telegram.org/file/bot${token}/${filePath}`;
  const loc = sd.pending[chatId];
  if(!loc){
    await reply.call(this, '⚠️ No tengo tu ubicación. Envía primero 📎 → Ubicación y luego la foto.');
    out = { handled:'photo_sin_ubicacion', url };
  } else {
    const rec = { id:String(msg.message_id), url, caption: msg.caption||'', date:new Date((msg.date||0)*1000).toISOString(), lat: loc.lat, lon: loc.lon };
    sd.photos.push(rec);
    if(sd.photos.length>500) sd.photos.shift();
    delete sd.pending[chatId];
    await reply.call(this, `✅ Foto ubicada en ${loc.lat.toFixed(5)}, ${loc.lon.toFixed(5)}. Total: ${sd.photos.length}.`);
    out = { handled:'foto', rec };
  }
}
return [{ json: out }];

// Devuelve el arreglo acumulado de fotos geolocalizadas.
const sd = $getWorkflowStaticData('global');
return [{ json: { photos: sd.photos || [] } }];
